import { GoogleGenAI } from "@google/genai";
import { CartItem } from '../types';

const getClient = () => {
    const apiKey = process.env.API_KEY;
    if (!apiKey) return null;
    return new GoogleGenAI({ apiKey });
};

export const generateReceiptMessage = async (items: CartItem[]): Promise<string> => {
  const ai = getClient();
  if (!ai) return "¡Gracias por su visita! Disfrute su postre.";

  const itemNames = items.map(i => i.name).join(', ');

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Escribe una frase corta, divertida y amable (máximo 15 palabras) para poner al final de un ticket de compra de una heladería. 
      El cliente compró: ${itemNames}. 
      Usa un tono alegre. No uses hashtags.`,
      config: {
        thinkingConfig: { thinkingBudget: 0 } 
      }
    });

    return response.text?.trim() || "¡Gracias por su visita! Disfrute su postre.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "¡Gracias por su visita! Disfrute su postre.";
  }
};

import React from 'react';
import { Order } from '../types';

interface ReceiptProps {
  order: Order | null;
}

const Receipt: React.FC<ReceiptProps> = ({ order }) => {
  if (!order) return null;

  return (
    <div id="printable-receipt" className="hidden print:block font-mono text-black p-2 max-w-[80mm] mx-auto text-xs leading-tight">
      <div className="text-center mb-4">
        <h1 className="text-xl font-bold uppercase mb-1">Gelato Shop</h1>
        <p>Av. Principal #123, Centro</p>
        <p>Tel: 555-0000</p>
        <p className="mt-2">{order.date.toLocaleDateString()} {order.date.toLocaleTimeString()}</p>
        <p>Ticket: #{order.id.slice(0, 8)}</p>
      </div>

      <div className="border-b-2 border-dashed border-black my-2"></div>

      <table className="w-full text-left">
        <thead>
          <tr>
            <th className="py-1">Cant</th>
            <th className="py-1">Prod</th>
            <th className="py-1 text-right">Tot</th>
          </tr>
        </thead>
        <tbody>
          {order.items.map((item, idx) => (
            <tr key={`${item.id}-${idx}`}>
              <td className="align-top py-1">{item.quantity}</td>
              <td className="align-top py-1">{item.name}</td>
              <td className="align-top text-right py-1">${(item.price * item.quantity).toFixed(2)}</td>
            </tr>
          ))}
        </tbody>
      </table>

      <div className="border-b-2 border-dashed border-black my-2"></div>

      <div className="flex justify-between font-bold text-sm">
        <span>TOTAL</span>
        <span>${order.total.toFixed(2)}</span>
      </div>

      <div className="flex justify-between text-xs mt-1">
        <span>Pago ({order.paymentMethod})</span>
        <span>${(order.receivedAmount || order.total).toFixed(2)}</span>
      </div>

      {order.change !== undefined && order.change > 0 && (
        <div className="flex justify-between text-xs mt-1">
          <span>Cambio</span>
