      />

      {isAdminOpen && (
        <AdminPanel onClose={() => setIsAdminOpen(false)} />
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { X, Save, Plus, Trash2, Edit2, Store, Package, Layers, BarChart3, Upload, Image as ImageIcon } from 'lucide-react';
