}

export interface Product {
  id: string;
  name: string;
  price: number;
  category: string; // References Category.id
  color: string; // Tailwind color class helper
}

export interface CartItem extends Product {
  quantity: number;
  notes?: string;
}

export interface Order {
  id: string;
  items: CartItem[];
  subtotal: number;
  tax: number;
  total: number;
  date: Date;
  paymentMethod: 'EFECTIVO' | 'TARJETA';
  receivedAmount?: number;
  change?: number;
  aiMessage?: string;
}

export interface StoreState {
  businessName: string;
  receiptLogo: string | null; // Base64 string for the image
  categories: Category[];
  products: Product[];
  orders: Order[];
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addCategory: (category: Category) => void;
  updateCategory: (category: Category) => void;
  deleteCategory: (id: string) => void;
  updateBusinessName: (name: string) => void;
  updateReceiptLogo: (base64: string | null) => void;
  addOrder: (order: Order) => void;
}

import React, { createContext, useContext, useState, useEffect } from 'react';
import { Product, Category, StoreState, Order } from '../types';
import { DEFAULT_CATEGORIES, DEFAULT_PRODUCTS } from '../constants';

const StoreContext = createContext<StoreState | undefined>(undefined);

export const StoreProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [businessName, setBusinessName] = useState(() => {
    return localStorage.getItem('pos_business_name') || "La Colonial";
  });

  const [receiptLogo, setReceiptLogo] = useState<string | null>(() => {
    return localStorage.getItem('pos_receipt_logo') || null;
  });

  const [categories, setCategories] = useState<Category[]>(() => {
    const saved = localStorage.getItem('pos_categories');
    return saved ? JSON.parse(saved) : DEFAULT_CATEGORIES;
  });

  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('pos_products');
    return saved ? JSON.parse(saved) : DEFAULT_PRODUCTS;
  });

  const [orders, setOrders] = useState<Order[]>(() => {
    const saved = localStorage.getItem('pos_orders');
    if (saved) {
      try {
        const parsed = JSON.parse(saved);
        // Rehydrate Date objects from strings
        return parsed.map((o: any) => ({
          ...o,
          date: new Date(o.date)
        }));
      } catch (e) {
        return [];
      }
    }
    return [];
  });

  // Persistence effects
  useEffect(() => {
    localStorage.setItem('pos_business_name', businessName);
    document.title = `${businessName} - Punto de Venta`;
  }, [businessName]);

  useEffect(() => {
    if (receiptLogo) {
      localStorage.setItem('pos_receipt_logo', receiptLogo);
    } else {
      localStorage.removeItem('pos_receipt_logo');
    }
  }, [receiptLogo]);

  useEffect(() => {
    localStorage.setItem('pos_categories', JSON.stringify(categories));
  }, [categories]);

  useEffect(() => {
    localStorage.setItem('pos_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('pos_orders', JSON.stringify(orders));
  }, [orders]);

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const addCategory = (category: Category) => {
    setCategories(prev => [...prev, category]);
  };

  const updateCategory = (updatedCategory: Category) => {
    setCategories(prev => prev.map(c => c.id === updatedCategory.id ? updatedCategory : c));
  };

  const deleteCategory = (id: string) => {
    setCategories(prev => prev.filter(c => c.id !== id));
  };

  const updateBusinessName = (name: string) => {
    setBusinessName(name);
  };

  const updateReceiptLogo = (base64: string | null) => {
    setReceiptLogo(base64);
  };

  const addOrder = (order: Order) => {
    setOrders(prev => [order, ...prev]); // Add new order to start of list
  };

  return (
    <StoreContext.Provider value={{
      businessName,
      receiptLogo,
      categories,
      products,
      orders,
      addProduct,
      updateProduct,
      deleteProduct,
      addCategory,
      updateCategory,
      deleteCategory,
      updateBusinessName,
      updateReceiptLogo,
      addOrder
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (context === undefined) {
    throw new Error('useStore must be used within a StoreProvider');
  }
  return context;
};

