          </h2>
          <button 
            onClick={clearCart} 
            disabled={cart.length === 0}
            className="p-2 text-red-500 hover:bg-red-50 rounded-lg disabled:opacity-30 transition-colors"
          >
            <Trash2 size={20} />
          </button>
        </div>

        {/* Cart Items List */}
