                title="Reimprimir último ticket"
              >
                <Printer size={24} />
              </button>
           </div>
        </div>
      </div>

      <PaymentModal 
        total={cartTotal}
        isOpen={isPaymentModalOpen}
        onClose={() => setIsPaymentModalOpen(false)}
        onConfirm={handlePayment}
        isProcessing={isProcessing}
      />

      {isAdminOpen && (
        <AdminPanel onClose={() => setIsAdminOpen(false)} />
      )}
    </div>
  );
};

export default App;

