                                <Edit2 size={18} />
                              </button>
                              <button onClick={() => { if(confirm('¿Eliminar producto?')) deleteProduct(product.id) }} className="p-2 text-red-500 hover:bg-red-50 rounded-lg">
                                <Trash2 size={18} />
                              </button>
                            </div>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
              </div>
            )}

            {/* CATEGORIES TAB */}
            {activeTab === 'CATEGORIES' && (
              <div className="space-y-4">
