                        <th className="p-4 text-right">Acciones</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y">
                      {categories.map(cat => (
                        <tr key={cat.id} className="hover:bg-gray-50">
                          <td className="p-4">
                             <div className={`w-10 h-10 rounded-lg flex items-center justify-center ${cat.color}`}>
